var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"인덱스, 휘몰아쳐라……!","JPN":"吹きつけろ、インデックス……！","ENG":"Index, sweep them away...!","TWN":"索引，捲動吧……！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_PRIDE"}}}},{"id":"L5_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_PR","text":{"KOREA":"쓸어버려, 베이비!","JPN":"一掃してやる！　ベイビー！","ENG":"Let's wipe them out, baby!","TWN":"掃蕩一切吧，寶貝！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"커헉……!","JPN":"がはっ……！","ENG":"Gah...!","TWN":"咳啊……！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_SWORD_MOVEMENT"},{"id":"L12_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"괴기한 모습이로군요, 변절자.","JPN":"怪奇な姿ですね、変節者。","ENG":"A grotesque sight even for you, betrayer.","TWN":"你的樣子真奇怪，叛徒。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L13_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"몸이 썩어 들어가는 동시에 상처가 아물고 있다니…….","JPN":"体が腐ると同時に傷が癒やされている……","ENG":"Your body rotting even as your wounds heal...","TWN":"身體腐爛的同時，傷口卻在癒合……"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그 추한 꼴이 주님의 뜻을 반하고, 신성에 다다른 결과인가요?","JPN":"その醜い姿が主の意思に反して、神聖にたどり着いた結果ですか？","ENG":"Is this hideous form the result of defying the Lord and reaching Divinity?","TWN":"這種醜陋的姿態就是違逆主的旨意，抵達神性的結果嗎？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"마음대로 지껄이도록. 어차피 범인의 이해를 바라지 않으니까.","JPN":"勝手にほざけ。どうせ凡人の理解など求めていない。","ENG":"Say whatever you like. I never expected an ordinary person to understand.","TWN":"隨你怎麼說。我本來就不期待凡人會理解。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"내 신앙은 언제나 스스로가 믿는 것을 행할 뿐이지.","JPN":"私の信仰は常に自らが信じることを行うだけだ。","ENG":"My faith has always been about acting on what I believe.","TWN":"我的信仰，是無論何時只做我所相信的事。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_PR","text":{"KOREA":"재수 없는 소리하는 건, 예전이나 지금이나 똑같네.","JPN":"鼻につくこと言うのは昔も今も変わらないな。","ENG":"You've always had a talent for spewing rotten nonsense.","TWN":"真是討厭的說法，從以前到現在都一樣。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_PR","text":{"KOREA":"어디 계속 그렇게 지껄여 댈 수 있는지 볼까!","JPN":"いつまでそうやってぬかしていられるか、やってみようじゃないか！","ENG":"Let's see how long you can keep flapping that mouth!","TWN":"來啊，我倒要看看你能嘴硬到什麼時候！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_PRIDE"}}}},{"id":"L23_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"계시의 때가 머지않았군…….","JPN":"啓示の時が近い……","ENG":"The time of revelation draws near...","TWN":"啟示的時刻，就快到了……"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L24_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"어차피 네놈들은 여기서 나를 잡을 수 없다.","JPN":"どうせ貴様らがここで私を捕まえることはできない。","ENG":"You cannot capture me here, regardless.","TWN":"反正你們也抓不到我。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"그러니 이쯤에서 시간 낭비는 그만두도록 하지.","JPN":"時間を無駄にするのはここまでにしよう。","ENG":"So let us stop wasting time.","TWN":"就此停止浪費時間吧。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_SWORD_MOVEMENT"},{"id":"L28_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"무슨? 스스로 가슴을 찔렀다고……?","JPN":"なっ……？　自分で胸を刺した……？","ENG":"What? He stabbed his own chest...?","TWN":"什麼？自己刺穿了胸口……？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_PR","text":{"KOREA":"완전 슬래셔 무비가 따로 없잖아?","JPN":"スラッシャー映画じゃん。","ENG":"This is straight out of a slasher movie.","TWN":"這根本就是血腥殺人電影吧？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_SURPRISE"}}}},{"id":"L31_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"신성이 녹아 있는 피를 내 검에 먹였다.","JPN":"神聖が溶け込んでいる血を私の剣に飲ませた。","ENG":"I fed my blade blood infused with Divinity.","TWN":"我已經讓浸染神性的血，吞噬了我的劍。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_FIRE_02"},{"id":"L32_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"순도가 높은 신성은 아니지만, 네놈들을 상대하기에는 이정도로 충분하겠지.","JPN":"純度の高い神聖ではないが、貴様ら相手にはこの程度で十分だろう。","ENG":"It may not be pure Divinity, but it should suffice to deal with you.","TWN":"雖然純度不高，但對付你們綽綽有餘了。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_QM","text":{"KOREA":"그래? 그렇다면 내 검과 정정당당히 겨루어 보지 않겠나?","JPN":"そうか？　ならば私の剣と正々堂々勝負してみないか？","ENG":"Oh? Then why not formally challenge me and my blade to a duel?","TWN":"是嗎？那就和我的劍堂堂正正一決勝負吧？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_QM","text":{"KOREA":"네놈의 정의가 정말로 올바르다면 말이야.","JPN":"貴様の正義が本当に正しいものなら。","ENG":"If you truly believe your justice is righteous.","TWN":"如果你的正義真的正確的話。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"큭, 설마……?","JPN":"くっ、まさか……？","ENG":"Kgh, impossible...","TWN":"呃，該不會……？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_04"},{"id":"L39_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"무구 개방!","JPN":"武具開放！","ENG":"Armament unleashed!","TWN":"武裝解放！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"파도 쳐라, 섬광──────────!!","JPN":"うなれ、閃光──────────！！","ENG":"Surge, Flash──────────!!","TWN":"翻湧吧，閃光────────！！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"순식간에 하늘이 갈라졌어… 대체 이 위력은……?","JPN":"あっという間に空が切り裂かれた……いったいこの威力は……？","ENG":"The sky split in an instant... What kind of power is that...?","TWN":"天空在瞬間被劈裂了……這威力到底是……？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_WIND"},{"id":"L45_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_PR","text":{"KOREA":"꺽다리는? 꺽다리는 어떻게 됐어……?","JPN":"のっぽは？　のっぽはどこだ……？","ENG":"What about Long Legs? What happened to him...?","TWN":"高個子呢？高個子怎麼樣了……？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_SURPRISE"}}}},{"id":"L47_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"아쉽지만, 도주한 것 같군요.","JPN":"残念ですが、逃走したようです。","ENG":"Regrettably, it seems he escaped.","TWN":"很遺憾，他好像逃走了。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L48_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"마지막 순간, 정면으로 받아 치지 않고, 궤도를 비트는데 힘을 사용했어요.","JPN":"最後の瞬間、攻撃を正面から受け止めず、軌道の修正に力を使っていました。","ENG":"At the last moment, he diverted the trajectory instead of meeting it head-on.","TWN":"他在最後一刻沒有正面迎戰，而是運用力量偏移軌道。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"큰 부상을 입었으니, 그리 멀리 가지는 못했을 겁니다.","JPN":"深手を負っているので、そう遠くまでは行けないはずです。","ENG":"He sustained severe injuries, so he couldn't have gone far.","TWN":"他受了重傷，應該跑不遠。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그 푸른 복장…….","JPN":"その青い装束……","ENG":"That blue uniform...","TWN":"那身藍色裝束……"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그렇다면, 당신이 소문으로만 듣던 조디악 나이츠의 단장이시군요.","JPN":"あなたが噂のゾディアックナイツの団長ですね。","ENG":"You must be the Captain of the Zodiac Knights I have only heard rumors of.","TWN":"原來如此，你就是傳聞中的十二宮騎士團團長吧。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"소개가 늦었습니다. 심의회.","JPN":"名乗るのが遅れました、審議会。","ENG":"My apologies for the late introduction, Investigation Council.","TWN":"自我介紹晚了，議會的。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"조디악 나이츠 단장, 에스테로사라고 합니다.","JPN":"ゾディアックナイツの団長、エステロサと申します。","ENG":"I am Esterosa, Captain of the Zodiac Knights.","TWN":"我是十二宮騎士團團長──艾斯特洛索。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"이렇게 강한 분께서 성황청의 성무에 협조해 주시니 영광이로군요.","JPN":"こんなに強い方が聖皇庁の聖務に力を貸してくださって光栄です。","ENG":"It is an honor to have someone of your strength aiding the Holy Curia's sacred mission.","TWN":"能有如此厲害的強者協助聖皇廳的聖務，實屬榮幸。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"하지만 단장님, 지금 즉시 그 변절자를 추적해야 합니다.","JPN":"ですが団長、今すぐあの変節者を追わねばなりません。","ENG":"But Captain, we must pursue that betrayer immediately.","TWN":"不過團長，現在必須立刻追擊那名叛徒。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그 자는 초월적인 재생 능력을 손에 넣었습니다. 금세 부상을 회복하겠죠.","JPN":"あの者は超越的な再生能力を手に入れています。傷はすぐに回復するはずです。","ENG":"He has obtained a transcendent regenerative ability. He will recover quickly.","TWN":"他已獲得超乎常理的再生能力，很快就會恢復。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"이대로 그 자를 놔두면, 무슨 일이 벌어질 지 모릅니다.","JPN":"このまま放っておけば、何が起こるかわかりません。","ENG":"If we let him go like this, there is no telling what may happen.","TWN":"若放任不管，後果不堪設想。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"대략적인 이야기는 레온하르트 경에게 들었습니다만…….","JPN":"大体の話はレオンハルト卿から聞いていますが……","ENG":"I've heard the general story from Dame Leonhardt, however...","TWN":"我已從里恩哈特卿那裡聽說大致情況了……"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"유감스럽게도 저희가 맡은 역할은 그 자를 쫓는 것이 아닙니다.","JPN":"残念ながら、私たちに任された役目は彼を追うことではありません。","ENG":"Regrettably, pursuing him is not our assigned role.","TWN":"但很遺憾，我們的任務並不是追擊他。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"네? 그게 무슨……?","JPN":"え？　それはどういう……？","ENG":"What? What do you mean...?","TWN":"什麼？那是什麼意思……？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"단장님, 찾았습니다!","JPN":"団長、見つかりました！","ENG":"Captain, we found her!","TWN":"團長，找到了！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L20_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"레온하르트 경이 말한 인상착의와 동일한 여학생입니다!","JPN":"レオンハルト卿が言っていた容姿と一致する女子生徒です！","ENG":"She matches the appearance Dame Leonhardt described.","TWN":"與里恩哈特卿描述完全一致的女學生！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그렇군요, 조디악 나이츠가 이곳에 온 이유는 요인 구출이었어요.","JPN":"なるほど。ゾディアックナイツがここに来た理由は要人の救出だったのですね。","ENG":"I see. The reason the Zodiac Knights came here was to extract her.","TWN":"原來如此。十二宮騎士團出現在這裡的理由，是為了救人。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L23_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"그렇습니다, 수녀님.","JPN":"はい、シスター。","ENG":"That is correct, Sister.","TWN":"沒錯，修女。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"저희 조디악 나이츠가 맡은 임무는 리오나 하트의 구출…….","JPN":"我々ゾディアックナイツの任務は、リオナ・ハートの救出……","ENG":"The mission entrusted to the Zodiac Knights is the rescue of Liona Hartt...","TWN":"我們十二宮騎士團的任務是救出萊歐娜．哈特……"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"그리고 샤레이드에 출몰한 제5종 침식체, 바루나스트라의 섬멸입니다.","JPN":"そしてシャレードに出現した第5種侵食体、ヴァルナストラの殲滅です。","ENG":"And the extermination of the Category 5 C.O. that appeared in Charade, Varunastra.","TWN":"以及殲滅出現在查雷德的第5類侵蝕體，伐樓拿之艦。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};